{
  "global": "Modify seaborn's Nominal scale (and inferred nominal scales) to replicate the three categorical-axis behaviors: ±0.5 tight limits via sticky-edge artist, grid suppression, and y-axis inversion.",
  "subtasks": [
    {
      "subtask": "Locate and understand the existing categorical axis treatment in seaborn's codebase to identify patterns to replicate for Nominal scales",
      "atomics": [
        "Search for the code that sets ±0.5 limits on categorical axes in categorical.py or _core/",
        "Identify where grid suppression logic lives for categorical plots",
        "Identify where y-axis inversion is applied for categorical plots",
        "Find where Nominal scale is defined and where scale type is inferred in _core/scales.py"
      ]
    },
    {
      "subtask": "Implement ±0.5 tight axis limits for Nominal scales using a sticky-edge invisible artist approach",
      "atomics": [
        "In the Nominal scale's setup or finalize method, add an invisible Line2D or Rectangle artist with sticky_edges set to hold the ±0.5 extent around the first and last tick",
        "Set ax.margins(axis=0) on the nominal axis so normal margin logic does not expand beyond the sticky edges",
        "Ensure this applies both when Nominal is on x and on y axes"
      ]
    },
    {
      "subtask": "Suppress grid lines on the Nominal (categorical) axis in Plotter._finalize_figure",
      "atomics": [
        "Detect which axes carry a Nominal scale by inspecting the scale objects stored on the Plotter after setup",
        "Call ax.grid(False, axis='x') or ax.grid(False, axis='y') on the nominal axis without overriding the non-nominal axis grid",
        "Check theme/rcParams to allow user overrides: only suppress the grid if the user has not explicitly requested it via the theme"
      ]
    },
    {
      "subtask": "Invert the y-axis when a Nominal scale is assigned to the y dimension",
      "atomics": [
        "In _finalize_figure or the Nominal scale's finalize step, detect if the Nominal scale is on the y-axis",
        "Call ax.invert_yaxis() for those axes, guarding against double-inversion if already inverted"
      ]
    },
    {
      "subtask": "Add or update tests to verify all three Nominal axis behaviors",
      "atomics": [
        "Write a test that checks ax.get_ylim() / ax.get_xlim() are within ±0.5 of the first and last tick for a Nominal x and y scale",
        "Write a test that grid lines are off on the nominal axis with a gridded theme active",
        "Write a test that the y-axis is inverted when Nominal is on y, and not inverted when on x"
      ]
    }
  ],
  "global_atomics": [
    "Run the full seaborn test suite to ensure no regressions in existing categorical or scale tests",
    "Verify behavior with an inferred Nominal scale (non-explicit) triggers the same three treatments as an explicitly declared so.Nominal()"
  ],
  "gold_actions": {
    "global": "Patch _core/scales.py Nominal class and Plotter._finalize_figure in _core/plot.py to add sticky-edge artist for ±0.5 limits, suppress the grid on the nominal axis, and invert the y-axis when Nominal is on y.",
    "subtasks": [
      {
        "subtask": "Read seaborn/_core/scales.py for Nominal, seaborn/_core/plot.py for _finalize_figure, and seaborn/categorical.py for existing categorical axis setup logic",
        "atomics": [
          "Grep for 'sticky_edges', 'invert_yaxis', and 'grid' in seaborn/_core/ and seaborn/categorical.py to map existing patterns",
          "Read the Nominal class in _core/scales.py to find _setup and _finalize hooks",
          "Read Plotter._finalize_figure in _core/plot.py to understand where per-axis post-processing occurs",
          "Confirm how scale type (Nominal vs Continuous) is stored and accessible from the Plotter at finalize time"
        ]
      },
      {
        "subtask": "Add an invisible artist with sticky edges ±0.5 around ticks and set margin=0 on the nominal axis",
        "atomics": [
          "In Nominal._finalize (or equivalent), call ax.add_artist(matplotlib.lines.Line2D([min-0.5, max+0.5], [0,0], alpha=0)) with sticky_edges.x populated so the view limits snap to ±0.5",
          "Call ax.margins(x=0) or ax.margins(y=0) on the nominal axis to disable matplotlib's default 5% margin expansion",
          "Branch on whether the scale is on 'x' or 'y' to apply the correct sticky-edge dimension"
        ]
      },
      {
        "subtask": "In Plotter._finalize_figure, iterate over subplot axes, detect Nominal scale presence, and call ax.grid(False) on the nominal axis dimension",
        "atomics": [
          "Access the stored scale mapping (e.g., self._scales) inside _finalize_figure to check if 'x' or 'y' is Nominal",
          "Call ax.grid(False, axis='x') when x is Nominal and ax.grid(False, axis='y') when y is Nominal, leaving the other axis grid intact",
          "Guard with a check against rcParams['axes.grid'] or theme settings so an explicit grid=True theme override is respected"
        ]
      },
      {
        "subtask": "In Plotter._finalize_figure, call ax.invert_yaxis() when the y scale is Nominal and the axis is not already inverted",
        "atomics": [
          "Check isinstance(self._scales.get('y'), Nominal) inside _finalize_figure",
          "Call ax.invert_yaxis() only if ax.yaxis_inverted() returns False to avoid double-inversion"
        ]
      },
      {
        "subtask": "Add pytest tests in tests/_core/test_scales.py and tests/_core/test_plot.py covering all three behaviors",
        "atomics": [
          "Assert ax.get_xlim() == (-0.5, n-0.5) for a plot with Nominal x scale having n unique values",
          "Assert ax.yaxis.get_gridlines() are not visible when Nominal is on y with a style that normally shows a grid",
          "Assert ax.yaxis_inverted() is True when Nominal is on y and False when Nominal is on x"
        ]
      }
    ],
    "global_atomics": [
      "Run 'python -m pytest tests/ -x -q' and confirm zero failures before and after the patch",
      "Construct a minimal plot using an inferred Nominal scale (passing a string-typed column without explicit so.Nominal()) and assert all three axis behaviors fire identically to the explicit case"
    ]
  }
}
